#!/bin/bash

# Setup script to configure environment from .env.test

echo "Setting up environment from .env.test..."

# Export the ADMIN_TOKEN from the ANTHROPIC_API_KEY in .env.test
ADMIN_TOKEN_VALUE=$(grep -E '^ANTHROPIC_API_KEY=' .env.test | cut -d'=' -f2-)
export ADMIN_TOKEN="$ADMIN_TOKEN_VALUE"

# Export other environment variables from .env.test
export DATABASE_URL=$(grep -E '^DATABASE_URL=' .env.test | cut -d'=' -f2-)
export AWS_ACCESS_KEY_ID=$(grep -E '^AWS_ACCESS_KEY_ID=' .env.test | cut -d'=' -f2-)
export AWS_SECRET_ACCESS_KEY=$(grep -E '^AWS_SECRET_ACCESS_KEY=' .env.test | cut -d'=' -f2-)
export STRIPE_SECRET_KEY=$(grep -E '^STRIPE_SECRET_KEY=' .env.test | cut -d'=' -f2-)
export LOGFIRE_TOKEN=$(grep -E '^LOGFIRE_TOKEN=' .env.test | cut -d'=' -f2-)

echo "Environment variables configured successfully!"
echo "ADMIN_TOKEN has been set from ANTHROPIC_API_KEY"
